```class Solution {
    public int subarrayGCD(int[] nums, int k) {
        int count = 0;
        for (int i = 0; i < nums.length; i++) {
            for (int j = i; j < nums.length; j++) {
                int gcd = nums[j];
                for (int m = j; m >= i; m--) {
                    gcd = gcd(gcd, nums[m]);
                }
                if (gcd == k) {
                    count++;
                }
            }
        }
        return count;
    }
    public int gcd(int a, int b) {
        return b == 0 ? a : gcd(b, a % b);
    }
}```
